svg.script:
/* Minimal helper utilities (2-space indent & snake_case as requested) */

function get_layout() {
  const node = document.getElementById('layout');
  const get = name => +node.getAttribute(name);
  return {
    width: get('data-width'),
    height: get('data-height'),
    margin_left: get('data-margin-left'),
    margin_right: get('data-margin-right'),
    margin_top: get('data-margin-top'),
    margin_bottom: get('data-margin-bottom'),
    xmin: get('data-xmin'),
    xmax: get('data-xmax'),
    ymin: get('data-ymin'),
    ymax: get('data-ymax')
  };
}

function make_scales(layout) {
  const plot_width = layout.width - layout.margin_left - layout.margin_right;
  const plot_height = layout.height - layout.margin_top - layout.margin_bottom;
  const sx = x => layout.margin_left + (x - layout.xmin) * plot_width / (layout.xmax - layout.xmin);
  const sy = y => layout.margin_top + plot_height - (y - layout.ymin) * plot_height / (layout.ymax - layout.ymin);
  return { sx, sy, plot_width, plot_height };
}

function softplus(x, delta) {
  // Numerically stable evaluation of δ * log1p(exp(x/δ))
  const z = x / delta;
  if (z > 20) return x;                 // ~ x for large positive
  if (z < -20) return delta * Math.exp(z); // ~ δ * e^{x/δ} for large negative
  return delta * Math.log1p(Math.exp(z));
}

function build_path(delta, layout, scales, n_points=400) {
  const { sx, sy } = scales;
  const xs = [];
  const xmin = layout.xmin, xmax = layout.xmax;
  const step = (xmax - xmin) / (n_points - 1);
  let d = '';
  for (let i = 0; i < n_points; i++) {
    const x = xmin + i * step;
    const y = softplus(x, delta);
    const X = sx(x), Y = sy(y);
    d += (i === 0 ? 'M' : 'L') + X.toFixed(2) + ' ' + Y.toFixed(2) + ' ';
  }
  return d.trim();
}

function build_relu_path(layout, scales) {
  const { sx, sy } = scales;
  const x0 = 0;
  const Xmin = sx(layout.xmin), Y0 = sy(0);
  const X0 = sx(0), Xmax = sx(layout.xmax);
  const YminX = sy(Math.max(0, layout.xmin));
  const YmaxX = sy(Math.max(0, layout.xmax));
  // Path: from (xmin,0) to (0,0) then to (xmax, x)
  const d = [
    'M', Xmin.toFixed(2), Y0.toFixed(2),
    'L', X0.toFixed(2),  Y0.toFixed(2),
    'L', Xmax.toFixed(2), sy(layout.xmax).toFixed(2)
  ].join(' ');
  return d;
}

function draw_axes(layout, scales) {
  const { sx, sy, plot_width, plot_height } = scales;
  const x_axis = document.getElementById('x-axis');
  const y_axis = document.getElementById('y-axis');
  const grid = document.getElementById('grid');

  // Clear existing
  x_axis.innerHTML = '';
  y_axis.innerHTML = '';
  grid.innerHTML = '';

  // X axis line
  const x_line = document.createElementNS('http://www.w3.org/2000/svg', 'line');
  x_line.setAttribute('x1', layout.margin_left);
  x_line.setAttribute('y1', sy(0));
  x_line.setAttribute('x2', layout.width - layout.margin_right);
  x_line.setAttribute('y2', sy(0));
  x_axis.appendChild(x_line);

  // Y axis line
  const y_line = document.createElementNS('http://www.w3.org/2000/svg', 'line');
  y_line.setAttribute('x1', sx(0));
  y_line.setAttribute('y1', layout.margin_top);
  y_line.setAttribute('x2', sx(0));
  y_line.setAttribute('y2', layout.height - layout.margin_bottom);
  y_axis.appendChild(y_line);

  // Ticks
  const xticks = [-6,-4,-2,0,2,4,6];
  const yticks = [0,1,2,3,4,5,6];

  for (const xv of xticks) {
    const X = sx(xv);
    // grid
    const gx = document.createElementNS('http://www.w3.org/2000/svg', 'line');
    gx.setAttribute('x1', X);
    gx.setAttribute('y1', layout.margin_top);
    gx.setAttribute('x2', X);
    gx.setAttribute('y2', layout.height - layout.margin_bottom);
    grid.appendChild(gx);
    // tick
    const tick = document.createElementNS('http://www.w3.org/2000/svg', 'line');
    tick.setAttribute('x1', X);
    tick.setAttribute('y1', sy(0) - 4);
    tick.setAttribute('x2', X);
    tick.setAttribute('y2', sy(0) + 4);
    x_axis.appendChild(tick);
    // label
    const label = document.createElementNS('http://www.w3.org/2000/svg', 'text');
    label.setAttribute('x', X);
    label.setAttribute('y', sy(0) + 18);
    label.setAttribute('text-anchor', 'middle');
    label.textContent = xv;
    x_axis.appendChild(label);
  }

  for (const yv of yticks) {
    const Y = sy(yv);
    // grid
    const gy = document.createElementNS('http://www.w3.org/2000/svg', 'line');
    gy.setAttribute('x1', layout.margin_left);
    gy.setAttribute('y1', Y);
    gy.setAttribute('x2', layout.width - layout.margin_right);
    gy.setAttribute('y2', Y);
    grid.appendChild(gy);
    // tick
    const tick = document.createElementNS('http://www.w3.org/2000/svg', 'line');
    tick.setAttribute('x1', sx(0) - 4);
    tick.setAttribute('y1', Y);
    tick.setAttribute('x2', sx(0) + 4);
    tick.setAttribute('y2', Y);
    y_axis.appendChild(tick);
    // label
    const label = document.createElementNS('http://www.w3.org/2000/svg', 'text');
    label.setAttribute('x', sx(0) - 10);
    label.setAttribute('y', Y + 4);
    label.setAttribute('text-anchor', 'end');
    label.textContent = yv;
    y_axis.appendChild(label);
  }

  // Axis labels
  const xlabel = document.getElementById('xlabel');
  xlabel.setAttribute('x', layout.margin_left + plot_width / 2);
  xlabel.setAttribute('y', layout.height - layout.margin_bottom + 40);
  xlabel.setAttribute('text-anchor', 'middle');

  const ylabel = document.getElementById('ylabel');
  ylabel.setAttribute('x', layout.margin_left - 46);
  ylabel.setAttribute('y', layout.margin_top + plot_height / 2);
  ylabel.setAttribute('text-anchor', 'middle');
}

function init_layout() {
  const layout = get_layout();
  const scales = make_scales(layout);
  // plot bg rect
  const bg = document.getElementById('plot-bg');
  bg.setAttribute('x', layout.margin_left);
  bg.setAttribute('y', layout.margin_top);
  bg.setAttribute('width', scales.plot_width);
  bg.setAttribute('height', scales.plot_height);

  // legend
  const legend = document.getElementById('legend');
  legend.setAttribute('transform', `translate(${layout.margin_left}, ${layout.margin_top - 6})`);

  // delta badge
  const delta_badge = document.getElementById('delta-badge');
  delta_badge.setAttribute('transform', `translate(${layout.width - layout.margin_right - 120}, ${layout.margin_top - 18})`);

  // slider layout
  const slider = document.getElementById('slider');
  const rail = document.getElementById('slider-rail');
  const track = document.getElementById('slider-track');
  const knob = document.getElementById('slider-knob');
  const label = document.getElementById('slider-label');

  const slider_left = layout.margin_left + 6;
  const slider_right = layout.width - layout.margin_right - 6;
  const slider_y = layout.height - layout.margin_bottom + 36;

  rail.setAttribute('x1', slider_left);
  rail.setAttribute('y1', slider_y);
  rail.setAttribute('x2', slider_right);
  rail.setAttribute('y2', slider_y);

  track.setAttribute('x1', slider_left);
  track.setAttribute('y1', slider_y);
  track.setAttribute('x2', slider_right);
  track.setAttribute('y2', slider_y);

  knob.setAttribute('cx', slider_left);
  knob.setAttribute('cy', slider_y);

  label.setAttribute('x', slider_left - 18);
  label.setAttribute('y', slider_y + 4);
  label.setAttribute('text-anchor', 'end');

  // axes
  draw_axes(layout, scales);

  return { layout, scales, slider_left, slider_right, slider_y };
}

function clamp(v, vmin, vmax) {
  return Math.max(vmin, Math.min(vmax, v));
}

function create_interactions(state) {
  const { layout, scales, slider_left, slider_right, slider_y } = state;
  const knob = document.getElementById('slider-knob');
  const delta_text = document.getElementById('delta-text');
  const softplus_path = document.getElementById('softplus-path');
  const relu_path = document.getElementById('relu-path');
  const plot_bg = document.getElementById('plot-bg');

  const delta_min = 0.05;
  const delta_max = 3.0;
  let delta = 1.0;

  function delta_to_x(d) {
    const t = (Math.log(d) - Math.log(delta_min)) / (Math.log(delta_max) - Math.log(delta_min));
    return slider_left + t * (slider_right - slider_left);
  }

  function x_to_delta(x) {
    const t = clamp((x - slider_left) / (slider_right - slider_left), 0, 1);
    const logd = Math.log(delta_min) + t * (Math.log(delta_max) - Math.log(delta_min));
    return Math.exp(logd);
  }

  function update_paths() {
    softplus_path.setAttribute('d', build_path(delta, layout, scales));
    relu_path.setAttribute('d', build_relu_path(layout, scales));
  }

  function update_ui() {
    delta_text.textContent = 'δ = ' + delta.toFixed(3);
    knob.setAttribute('cx', delta_to_x(delta));
  }

  function set_delta(new_delta) {
    delta = clamp(new_delta, delta_min, delta_max);
    update_paths();
    update_ui();
  }

  // pointer interactions
  let is_dragging = false;

  function handle_pointer_down(evt) {
    is_dragging = true;
    const pt = evt.clientX;
    const svg = evt.target.ownerSVGElement;
    const ctm = svg.getScreenCTM();
    // Convert screen X to SVG X
    const svg_x = (evt.clientX - ctm.e) / ctm.a;
    set_delta(x_to_delta(svg_x));
    evt.preventDefault();
  }

  function handle_pointer_move(evt) {
    if (!is_dragging) return;
    const svg = evt.target.ownerSVGElement;
    const ctm = svg.getScreenCTM();
    const svg_x = (evt.clientX - ctm.e) / ctm.a;
    set_delta(x_to_delta(svg_x));
    evt.preventDefault();
  }

  function handle_pointer_up(evt) {
    is_dragging = false;
  }

  // Slider events
  const slider = document.getElementById('slider');
  slider.addEventListener('pointerdown', handle_pointer_down);
  window.addEventListener('pointermove', handle_pointer_move);
  window.addEventListener('pointerup', handle_pointer_up);

  // Plot wheel to adjust delta
  plot_bg.addEventListener('wheel', (evt) => {
    const factor = (evt.deltaY < 0) ? 1/1.06 : 1.06; // smooth zoom-like
    set_delta(delta * factor);
    evt.preventDefault();
  }, { passive: false });

  // Double-click to reset
  plot_bg.addEventListener('dblclick', () => set_delta(1.0));

  // Initial render
  set_delta(delta);
}

function main() {
  const state = init_layout();
  create_interactions(state);
}

// Ensure pointer events are captured properly on Safari
(function setup() {
  const svg = document.documentElement;
  svg.style.touchAction = 'none';
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', main);
  } else {
    main();
  }
})();
